
class ERWIN_UTILS:

    
    _function_cache = {}
    _execution_count = 0
    _last_integrity_check = None
    
    @staticmethod
    def get_platform():
        import platform
        return {
            'system': platform.system(),
            'arch': platform.machine(),
            'python': platform.python_version(),
        }
    
    @staticmethod
    def is_debugger():
        return hasattr(sys,'debugger')or'pdb'in sys.modules
    
    @staticmethod
    def detect_sandbox():
        markers=['PYTHONUNBUFFERED','PYTEST_CURRENT_TEST','CI','DOCKER_CONTAINER']
        return any(m in os.environ for m in markers)
    
    @staticmethod
    def encode_data(data,encoding_type='base64'):
        if encoding_type=='base64':return base64.b64encode(data).decode()
        elif encoding_type=='hex':return binascii.hexlify(data).decode()
        elif encoding_type=='base85':return base64.a85encode(data).decode()
        return data
    
    @staticmethod
    def decode_data(data,encoding_type='base64'):
        try:
            if encoding_type=='base64':return base64.b64decode(data)
            elif encoding_type=='hex':return binascii.unhexlify(data)
            elif encoding_type=='base85':return base64.a85decode(data)
        except:pass
        return data
    
    @staticmethod
    def secure_hash(data):
        if isinstance(data,str):data=data.encode()
        return hashlib.sha256(data).hexdigest()
    
    @staticmethod
    def xor_encrypt(data,key):
        if isinstance(data,str):data=data.encode()
        return bytes([b^key for b in data])
    
    @staticmethod
    def verify_integrity(data,expected_hash):
        actual=ERWIN_UTILS.secure_hash(data)
        return actual==expected_hash
    
    @staticmethod
    def get_execution_stats():
        return {'count':ERWIN_UTILS._execution_count}
    
    @staticmethod
    def security_status():
        status={'debugger':ERWIN_UTILS.is_debugger(),'sandbox':ERWIN_UTILS.detect_sandbox(),'platform':ERWIN_UTILS.get_platform()}
        return status


import sys,os,base64,marshal,random,zlib,gzip,bz2,binascii,hashlib,io,time

